_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv1=vUv-0.5;
lav_gnd=  -min(texture(sampler_fc_main,vUv).b, texture(sampler_fc_main,vUv+hor.yx).b);

rsl = rs_lav(uv1,lav_gnd)+mov;
mod = texture(sampler_noise_mq,rsl.xy*.043+modran);

i=0, p=0;
for (int n=1; n <= quality; n++) {
  p =  ((lav_gnd+noise3 (rsl, mod))/quality);
  i += p;
  lav_gnd -= p*0.1+i*0.2;
  rsl = rs_lav(uv1,lav_gnd)+mov;
}
l = clamp01(-lav_gnd);

d=1.5;
dz = -1.2/rsl.z*xyscale*d*dir;

rsl3 = rsl * 8 + l*0;
ripple = ((noise2 (rsl3-dz) - noise2 (rsl3+dz))* (1-l))*1+0.02;

ripple = (1.2/rsl.z*ripple+noise3 (rsl-vec3 (dz,0),mod) - noise3 (rsl+vec3 (dz,0),mod))*(1-l)/d/sqrt(50+rsl.z)*3001;

ripple = .95-exp(-ripple);

ret.r = ripple;
ret.b = l;
ret = mix(ret,GetBlur1(vUv),0.2);
ret.g = rsl.z*xyscale*4;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

//vUv += uTexSize.zw/2;
uv0 = vUv;
rsl = rs_lav (vUv-0.5,-GetBlur1(vUv).b+modran.yx);
mod = texture(sampler_noise_mq, rsl*0.1);

ret0 = GetPixel(vUv);
dist = ret0.g;
struc = ret0.r;
height = 1-ret0.b;
snow = abs(height-GetBlur1(vUv).b)* (2*height*(0.0+struc))/dist*1;

//###########################
ret = ret0;;

ret.r = mix(ret0.r,GetBlur1(vUv).r,sat(2-6*(ret0.g+ret0.b*0.25))) ;

ret.b = pow(ret0.b,3)/2 + ret.r/2;
ret.g = pow(ret0.g,1.2) /2+ ret.r/2;
ret.rg = sat (ret.rg+lum(ret)/2) + ret.b*(mod.z-0.3)*0.5;

ret += ret0.r *pow(height,2)* vec3 (1, 1, 2)*2*sat(2-dist)*mod.x; //snow
//ret += snow;


ret *= 1;

//wolken
rsl = rs_lav (vUv-0.5,- sat(GetBlur1(vUv).b*0.7));
ret += noise2(3*rsl,GetBlur1(vUv).b).x * clamp01(4*ret0.b-3) / abs(rsl.z)*3*mod.y;

//Sonne
ret += sat(0.12/sqrt(length(vUv-vec2 (q2,0.58-q6))) * clamp01(1-height*1 + dist*2-1)) ;
//ret += pow(mix(1-vUv.x,vUv.x,dir)*(1-vUv.y),4) * clamp01(GetPixel(vUv).b*5 +GetPixel(vUv).g*2-1) * vec3(1,0.5,0.14);




  fragColor = ret;
}
